-- Supabase Database Schema for IPL Ticket Booking\n\n-- Create tables:\n-- Matches, Stands, Seats, the user is handled by auth.users\n-- Bookings\n\nCREATE TABLE matches (\n    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,\n    team_home TEXT NOT NULL,\n    team_away TEXT NOT NULL,\n    date_time TIMESTAMP WITH TIME ZONE NOT NULL,\n    stadium TEXT NOT NULL,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL\n);\n\nCREATE TABLE stands (\n    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,\n    match_id UUID REFERENCES matches(id) ON DELETE CASCADE,\n    name TEXT NOT NULL,\n    color TEXT NOT NULL,\n    price NUMERIC NOT NULL,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL\n);\n\nCREATE TABLE seats (\n    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,\n    stand_id UUID REFERENCES stands(id) ON DELETE CASCADE,\n    row_label TEXT NOT NULL,\n    seat_number INTEGER NOT NULL,\n    status TEXT NOT NULL CHECK (status IN ('Available', 'Selected', 'Booked')),\n    locked_by UUID, -- If 'Selected', user ID holding the lock\n    locked_at TIMESTAMP WITH TIME ZONE,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL\n);\n\nCREATE TABLE bookings (\n    id UUID DEFAULT uuid_generate_v4() PRIMARY KEY,\n    user_id UUID, -- References auth.users or custom users table if preferred\n    match_id UUID REFERENCES matches(id),\n    seat_id UUID REFERENCES seats(id),\n    amount NUMERIC NOT NULL,\n    status TEXT NOT NULL DEFAULT 'Confirmed',\n    payment_id TEXT,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL\n);\n\n-- Realtime setup\nALTER PUBLICATION supabase_realtime ADD TABLE seats;\n
